#!/usr/bin/env node
const fs = require("fs");
const path = require("path");
const { rebuildConnections } = require("./rebuild-connections");

const root = path.resolve(__dirname, "..");
const indexPath = path.join(root, "data", "glossary-index.json");
const faqIndexPath = path.join(root, "data", "faq-index.json");
const termsDir = path.join(root, "content", "terms");
const faqDir = path.join(root, "content", "faq");
const examplesDir = path.join(root, "content", "examples");
const outPath = path.join(root, "glossary-bundle.js");

const index = rebuildConnections(indexPath);
const faqIndex = JSON.parse(fs.readFileSync(faqIndexPath, "utf8"));
const descriptions = {};
const examples = {};
const faqArticles = {};

for (const term of index) {
  const mdPath = path.join(termsDir, `${term.id}.md`);
  if (!fs.existsSync(mdPath)) {
    console.error(`Missing markdown: content/terms/${term.id}.md`);
    process.exit(1);
  }
  descriptions[term.id] = fs.readFileSync(mdPath, "utf8");

  const exPath = path.join(examplesDir, `${term.id}.md`);
  if (fs.existsSync(exPath)) {
    examples[term.id] = fs.readFileSync(exPath, "utf8");
  }
}

for (const item of faqIndex) {
  const mdPath = path.join(faqDir, `${item.id}.md`);
  if (!fs.existsSync(mdPath)) {
    console.error(`Missing FAQ markdown: content/faq/${item.id}.md`);
    process.exit(1);
  }
  faqArticles[item.id] = fs.readFileSync(mdPath, "utf8");
}

const bundle = { index, descriptions, examples, faqIndex, faqArticles };
const output = `// Generated by scripts/build-bundle.js — GitHub Pages 배포용\nwindow.__GLOSSARY__ = ${JSON.stringify(bundle, null, 2)};\n`;

fs.writeFileSync(outPath, output);
console.log(`Built ${outPath} (${index.length} terms, ${Object.keys(examples).length} examples, ${faqIndex.length} faq)`);
console.log("로컬 확인: python3 -m http.server 8000  (빌드 없이 md/json 바로 반영)");
console.log("GitHub 배포: glossary-bundle.js 를 커밋 후 push");
